import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom'; // Ensure Link is imported
import { API_BASE_URL } from '../config'; // Import API_BASE_URL from config

const EventManage = () => {
  const [events, setEvents] = useState([]);

  useEffect(() => {
    const fetchEvents = async () => {
      eventer_id = localStorage.getItem('eventer_id');
      console.log(eventer_id); 
      const response = await fetch(`${API_BASE_URL}/event/get_event_by_eventer_id/${eventer_id}`); // Use API_BASE_URL to construct API URL
      const data = await response.json();
      console.log(data);
      setEvents(data);
    };
    fetchEvents();
  }, []);

  const filterEventsByState = (state) => {
    return events.filter(event => event.event_state === state);
  };

  return (
    <div>
      <h1>イベンター利用画面</h1>
      <h2>Draft Events</h2>
      {filterEventsByState('draft').map((event) => (
        <div key={event.event_id}>
          <Link to={`/event/${event.event_id}`}>{event.event_name}</Link>
        </div>
      ))}
      <h2>Open Events</h2>
      {filterEventsByState('open').map((event) => (
        <div key={event.event_id}>
          <Link to={`/event/${event.event_id}`}>{event.event_name}</Link>
        </div>
      ))}
      <h2>Close Events</h2>
      {filterEventsByState('close').map((event) => (
        <div key={event.event_id}>
          <Link to={`/event/${event.event_id}`}>{event.event_name}</Link>
        </div>
      ))}
      <h2>Rigister New Event</h2>
      <Link to="/event/register">Register New Event</Link>
      <h2>Go to Home</h2>
      <Link to="/home">Go to Home</Link>
    </div>
  );
};

export default EventManage;
